using UnityEngine;

public class Phase1 : MonoBehaviour
{
    public WriteTextSystem writeTextSystem;
    void Start()
    {
        writeTextSystem.WriteText("Buenos días. Gracias por recibirme con tan poca antelación. Mire, le cuento mi caso porque estoy verdaderamente desesperado y ya no sé qué hacer; esto me está quitando el sueño.\r\n\r\nEl problema viene por una reforma integral que quise hacer en una vivienda unifamiliar que heredé en la sierra. En marzo del año pasado, firmé un contrato de obra con una empresa constructora, 'Reformas Integrales Martínez S.L.'. El presupuesto total aceptado era de 45.000 euros, con fecha de finalización estipulada para el 15 de septiembre. Según lo acordado, les hice una transferencia de 22.500 euros en concepto de provisión de fondos para acopio de materiales y empezar a trabajar.\r\n\r\nAl principio todo iba bien, o eso parecía. Empezaron con las demoliciones en abril. Sin embargo, a partir de junio la cuadrilla dejó de ir. Cuando llamaba al encargado, todo eran excusas: que si había escasez de suministros, que si un trabajador estaba de baja... Pero lo peor no es el retraso. Lo peor es que, cuando contraté a un arquitecto técnico por mi cuenta para que fuera a revisar lo que habían hecho, nos llevamos las manos a la cabeza.\r\n\r\nResulta que tiraron un muro de carga que no estaba en el proyecto de demolición. Esto ha provocado unas grietas enormes en la estructura de la casa y, de rebote, ha afectado al muro colindante del vecino, que ya me ha amenazado con demandarme a mí. El perito que contraté ha elaborado un informe demoledor: subsanar los daños estructurales que han causado, reparar la medianera del vecino y terminar la obra que dejaron a medias asciende a un total de 34.200 euros.\r\n\r\nEn octubre intenté llegar a un acuerdo amistoso. Les envié un burofax con acuse de recibo y certificación de texto exigiéndoles la resolución del contrato por incumplimiento y la devolución de los importes no ejecutados, más los daños y perjuicios. Lo recibieron, pero me han ignorado por completo. Ahora ni siquiera me cogen el teléfono.\r\n\r\nNecesito que los llevemos a los juzgados. Tengo todas las facturas, el contrato firmado, los justificantes de las transferencias bancarias, el informe pericial y el burofax. ¿Cree que tenemos un caso sólido para ir a por ellos por la vía civil y recuperar mi dinero?");
    }

    // Update is called once per frame
    void Update()
    {
        
    }
}
